module decoder_2to4 (
    input [1:0] in,
    output reg [3:0] not_out
);

    // Decoder logic
    always @(*) begin
        case (in)
            2'b00: not_out = 4'b0001;
            2'b01: not_out = 4'b0010;
            2'b10: not_out = 4'b0100;
            2'b11: not_out = 4'b1000;
            default: not_out = 4'b0000;
        endcase
    end

endmodule
